import java.io.*;
import java.util.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Sanitize user input by encoding special characters
        String sanitizedUserName = Encode.forHtml(userName);

        // Output sanitized user input in the HTML response
        System.out.println("<p>Welcome, " + sanitizedUserName + "!</p>");

        scanner.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
